mapper.select:
SELECT p.*, o.owner_name AS owner, u.nick_name AS manager FROM sys_property_info p LEFT JOIN sys_owner_info o ON p.owner_id = o.owner_id LEFT JOIN sys_user u ON p.manager_id = u.user_id WHERE 1=1
AND p.property_address LIKE CONCAT('%', #{propertyAddress}, '%')
AND p.region = #{region}
AND p.status = #{status}

SELECT a.*
FROM sys_property_info a left join sys_owner_info b on a.owner_id = b.owner_id
WHERE  b.user_id = #{userId}

mapper.insert:
INSERT INTO sys_property_info (
    property_address, region, building_no, unit_no, floor, room_no,
    building_area, usable_area, owner_id, owner, manager_id, manager,
    property_type, status, image_url, create_time, remark
) VALUES (
             #{propertyAddress}, #{region}, #{buildingNo}, #{unitNo}, #{floor}, #{roomNo},
             #{buildingArea}, #{usableArea}, #{ownerId}, #{owner}, #{managerId}, #{manager},
             #{propertyType}, #{status}, #{imageUrl}, NOW(), #{remark}
         )

mapper.update:
UPDATE sys_property_info
property_address = #{propertyAddress}, region = #{region}, building_no = #{buildingNo}, unit_no = #{unitNo}, floor = #{floor}, room_no = #{roomNo}, building_area = #{buildingArea}, usable_area = #{usableArea}, owner_id = #{ownerId}, owner = #{owner}, manager_id = #{managerId}, manager = #{manager}, property_type = #{propertyType}, status = #{status}, image_url = #{imageUrl}, remark = #{remark}, update_time = NOW()
WHERE property_id = #{propertyId}

UPDATE sys_property_info
SET status = #{status}, update_time = NOW()
WHERE property_id = #{propertyId}

UPDATE sys_property_info
SET owner_id = #{ownerId}, owner = #{owner}, update_time = NOW(),manager_id=#{managerId}, manager=#{manager}
WHERE property_id = #{propertyId}
